// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *OutputMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockErrorInspect()

			m.MinimockErrorBoxInspect()

			m.MinimockErrorfInspect()

			m.MinimockInfoInspect()

			m.MinimockInfoBoxInspect()

			m.MinimockInfofInspect()

			m.MinimockNewPrefixOutputInspect()

			m.MinimockPrintInspect()

			m.MinimockPrintfInspect()

			m.MinimockRequestInspect()

			m.MinimockWarnInspect()

			m.MinimockWarnBoxInspect()

			m.MinimockWarnfInspect()

			m.MinimockWriteInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *OutputMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *OutputMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockErrorDone() &&
		m.MinimockErrorBoxDone() &&
		m.MinimockErrorfDone() &&
		m.MinimockInfoDone() &&
		m.MinimockInfoBoxDone() &&
		m.MinimockInfofDone() &&
		m.MinimockNewPrefixOutputDone() &&
		m.MinimockPrintDone() &&
		m.MinimockPrintfDone() &&
		m.MinimockRequestDone() &&
		m.MinimockWarnDone() &&
		m.MinimockWarnBoxDone() &&
		m.MinimockWarnfDone() &&
		m.MinimockWriteDone()
}
